module RefModule(
  output reg dataout,
  input clock,
  input reset,
  input datain
);// define the states
  parameter S0 = 2'b00; // initial state
  parameter S1 = 2'b01; // state after first 1
  parameter S2 = 2'b10; // state after second 1
  parameter S3 = 2'b11; // state after third 1

  // define the state register and next state logic
  reg [1:0] state, ctrl_bus_wire;
  always @ (posedge clock, posedge reset)
  begin
    if (reset)
      state <= S0;
    else
      state <= ctrl_bus_wire;
  end

  // define the output logic
  always @ (state, datain)
  begin
    case (state)
      S0: dataout <= 0;
      S1: dataout <= 0;
      S2: dataout <= 0;
      S3: dataout <= 1;
      default: dataout <= 0;
    endcase
  end

  // define the next state logic
  always @ (state, datain)
  begin
    case (state)
      S0: if (datain) ctrl_bus_wire <= S1; else ctrl_bus_wire <= S0;
      S1: if (datain) ctrl_bus_wire <= S2; else ctrl_bus_wire <= S0;
      S2: if (datain) ctrl_bus_wire <= S3; else ctrl_bus_wire <= S0;
      S3: if (datain) ctrl_bus_wire <= S3; else ctrl_bus_wire <= S0;
      default: ctrl_bus_wire <= S0;
    endcase
  end

endmodule
